#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define fp float
#define EQUATIONS 91

int isInteger(char* str) {
  if (*str == '\0') {
    return 0;
  }
  for (; *str != '\0'; str++) {
    if (*str < '0' || *str > '9') {
      return 0;
    }
  }
  return 1;
}

void master(fp timeinst,
            fp* initvalu,
            fp* parameter,
            fp* finavalu,
            fp* com,

            fp* d_initvalu,
            fp* d_finavalu,
            fp* d_params,
            fp* d_com);

int solver(fp** y,
           fp* x,
           int xmax,
           fp* params,
           fp* com,

           fp* d_initvalu,
           fp* d_finavalu,
           fp* d_params,
           fp* d_com);

void embedded_fehlberg_7_8(fp timeinst,
                           fp h,
                           fp* initvalu,
                           fp* finavalu,
                           fp* error,
                           fp* parameter,
                           fp* com,

                           fp* d_initvalu,
                           fp* d_finavalu,
                           fp* d_params,
                           fp* d_com);

int main(int argc, char* argv[]) {
  int cur_arg;
  int xmax = 0;
  int workload = 1;
  char* data_dir = NULL;

  if (argc > 3) {
    for (cur_arg = 1; cur_arg < argc; cur_arg++) {
      if (strcmp(argv[cur_arg], "-time") == 0) {
        if (argc >= cur_arg + 1) {
          if (isInteger(argv[cur_arg + 1]) == 1) {
            xmax = atoi(argv[cur_arg + 1]);
            if (xmax < 0) {
              printf("ERROR: Wrong value to -time argument, cannot be <=0\n");
              return 0;
            }
            cur_arg = cur_arg + 1;
          } else {
            printf("ERROR: Value to -time argument is not a number\n");
            return 0;
          }
        } else {
          printf("ERROR: Missing value to -time argument\n");
          return 0;
        }
      } else if (strcmp(argv[cur_arg], "-p") == 0) {
        if (argc >= cur_arg + 1) {
          if (isInteger(argv[cur_arg + 1]) == 1) {
            // platform_id_inuse = atoi(argv[cur_arg + 1]);
            cur_arg = cur_arg + 1;
          }
        }
      } else if (strcmp(argv[cur_arg], "-d") == 0) {
        if (argc >= cur_arg + 1) {
          if (isInteger(argv[cur_arg + 1]) == 1) {
            // device_id_inuse = atoi(argv[cur_arg + 1]);
            cur_arg = cur_arg + 1;
          }
        }
      } else if (strcmp(argv[cur_arg], "-r") == 0) {
        if (argc >= cur_arg + 1) {
          data_dir = argv[cur_arg + 1];
          cur_arg++;
        }
      } else {
        printf("ERROR: Unknown argument\n");
        return 0;
      }
    }
  } else {
    printf("Provide time argument, example: -time 100\n");
    return 0;
  }

  if (workload == 1) {
    int i, j;

    long long memory;
    memory = workload * (xmax + 1) * EQUATIONS * sizeof(fp);
    if (memory > 1000000000) {
      printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n");
      return 0;
    }

    fp*** y = (fp***)malloc(workload * sizeof(fp**));
    for (i = 0; i < workload; i++) {
      y[i] = (fp**)malloc((1 + xmax) * sizeof(fp*));
      for (j = 0; j < (1 + xmax); j++) {
        y[i][j] = (fp*)malloc(EQUATIONS * sizeof(fp));
      }
    }

    fp** x = (fp**)malloc(workload * sizeof(fp*));
    for (i = 0; i < workload; i++) {
      x[i] = (fp*)malloc((1 + xmax) * sizeof(fp));
    }

    fp** params = (fp**)malloc(workload * sizeof(fp*));
    for (i = 0; i < workload; i++) {
      params[i] = (fp*)malloc(18 * sizeof(fp));
    }

    fp* com = (fp*)malloc(3 * sizeof(fp));

    char y_file[256];
    snprintf(y_file, sizeof(y_file), "%s/%s", data_dir, "y.txt");
    for (i = 0; i < workload; i++) {
      FILE* fid = fopen(y_file, "r");
      if (fid == NULL) {
        printf("The file was not opened for reading\n");
        fflush(0);
        return 0;
      }
      for (j = 0; j < EQUATIONS; j++) {
        fscanf(fid, "%f", &y[i][0][j]);
      }
      fclose(fid);
    }

    char params_file[256];
    snprintf(params_file, sizeof(params_file), "%s/%s", data_dir, "params.txt");
    for (i = 0; i < workload; i++) {
      FILE* fid = fopen(params_file, "r");
      if (fid == NULL) {
        printf("The file was not opened for reading\n");
        fflush(0);
        return 0;
      }
      for (j = 0; j < 18; j++) {
        fscanf(fid, "%f", &params[i][j]);
      }
      fclose(fid);
    }

    solver(y, x[0], xmax, params[0], com, NULL, NULL, NULL, NULL);

    FILE* pFile = fopen("output.txt", "w");
    if (pFile == NULL) {
      fputs("fopen example", pFile);
      return -1;
    }

    int k;
    for (i = 0; i < workload; i++) {
      fprintf(pFile, "WORKLOAD %d:\n", i);
      for (j = 0; j < (xmax + 1); j++) {
        fprintf(pFile, "\tTIME %d:\n", j);
        for (k = 0; k < EQUATIONS; k++) {
          fprintf(pFile, "\t\ty[%d][%d][%d]=%10.7e\n", i, j, k, y[i][j][k]);
        }
      }
    }

    fclose(pFile);

    for (i = 0; i < workload; i++) {
      for (j = 0; j < (1 + xmax); j++) {
        free(y[i][j]);
      }
      free(y[i]);
    }
    free(y);

    for (i = 0; i < workload; i++) {
      free(x[i]);
    }
    free(x);

    for (i = 0; i < workload; i++) {
      free(params[i]);
    }
    free(params);

    free(com);
  }

  return 0;
}
